  var counts = new Map();
  for (var i = 0; i < cards.length; i++) {
    var v = cards[i].value;
    counts.set(v, (counts.get(v) || 0) + 1);
  }
  var values = Array.from(counts.keys()).sort(function(a, b) { return a - b; });
  var countVals = Array.from(counts.values());
  if (n === 4 && counts.size === 1) return { type: 'bomb', mainValue: values[0] };
  if (n === 1) return { type: 'single', mainValue: values[0] };
  if (n === 2 && counts.size === 1) return { type: 'pair', mainValue: values[0] };
  if (n === 3 && counts.size === 1) return { type: 'triple', mainValue: values[0] };
  if (n === 4 && countVals.indexOf(3) >= 0 && countVals.indexOf(1) >= 0) {
    var tv = values.find(function(v) { return counts.get(v) === 3; });
    return { type: 'triple_single', mainValue: tv };
  }
  if (n === 5 && countVals.indexOf(3) >= 0 && countVals.indexOf(2) >= 0) {
    var tv2 = values.find(function(v) { return counts.get(v) === 3; });
    return { type: 'triple_pair', mainValue: tv2 };
  }
